import { useEffect, useState } from "react";

function TypingText() {
  const text = `Интересный факт
  adaskdasdklasdlladadaskdasdklasdlladadaskdasdklasdlladadaskdasdklasdlladadaskdasdklasdllad
  asdasd
  asdasdasdas
  `
  
  ;
  const [displayedText, setDisplayedText] = useState("");

  useEffect(() => {
    let index = 0;
    const interval = setInterval(() => {
      setDisplayedText(text.slice(0, index));
      index++;
      if (index > text.length) clearInterval(interval);
    }, 80); // скорость печатания (меньше = быстрее)

    return () => clearInterval(interval);
  }, []);

  return <div className="typing-text" >{displayedText}</div>;
}

export default TypingText;
